import * as authentication from "../../src/lib/authentication";
import { generateToken } from "../jwtUtils";

describe("Authentication module", () => {
  afterEach(() => {
    window.localStorage.clear();
  });
  const goodJWTToken = generateToken(false);
  const simpleJWTToken =
    "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzaW1wbGUiOiJqd3QifQ.cvI09QALjVQp2xGC9VddagRnD1naJ5RKWT8-vfVh-uY";
  const errorJWTToken = "Error : There was an error! | 2019-02-05T08:56:18.273Z";

  const expiredJWTToken = generateToken(true);
  describe("getJwt function", () => {
    it("when called should return the null if nothing is stored against frJwt in localstorage", () => {
      expect(authentication.getJwt()).toBe(null);
    });
    it("when called should return the JWT stored against frJwt in localstorage", () => {
      let frJwt = goodJWTToken;
      window.localStorage.setItem("frJwt", frJwt);
      expect(authentication.getJwt()).toBe(frJwt);
    });
    it("when called should return the error and date stamp stored against frJwt in localstorage", () => {
      let frJwt = "Error : There was an error! | 2019-02-05T08:56:18.273Z",
        returnedJwt;
      window.localStorage.setItem("frJwt", frJwt);
      returnedJwt = authentication.getJwt();
      expect(returnedJwt.error).toBe("Error : There was an error!");
      expect(returnedJwt.failureDateStamp).toBe("2019-02-05T08:56:18.273Z");
    });
  });
  describe("getUsiJwt function", () => {
    it("when called should return the null if nothing is stored against usiJwt in localstorage", () => {
      expect(authentication.getUsiJwt()).toBe(null);
    });
    it("when called should return the JWT stored against usiJwt in localstorage", () => {
      let usiJwt = goodJWTToken;
      window.localStorage.setItem("usiJwt", usiJwt);
      expect(authentication.getUsiJwt()).toBe(usiJwt);
    });
    it("when called should return the error and date stamp stored against usiJwt in localstorage", () => {
      let usiJwt = "Error : There was an error! | 2019-02-05T08:56:18.273Z",
        returnedJwt;
      window.localStorage.setItem("usiJwt", usiJwt);
      returnedJwt = authentication.getUsiJwt();
      expect(returnedJwt.error).toBe("Error : There was an error!");
      expect(returnedJwt.failureDateStamp).toBe("2019-02-05T08:56:18.273Z");
    });
  });
  describe("getCustomerCode function", () => {
    it("when called should return the null if nothing is stored against customerCode in localstorage", () => {
      expect(authentication.getCustomerCode()).toBe(null);
    });
    it("when called should return the JWT stored against customerCode in localstorage", () => {
      let customerCode = "10000007951";
      window.localStorage.setItem("customerCode", customerCode);
      expect(authentication.getCustomerCode()).toBe(customerCode);
    });
  });
  describe("getUserCredential function", () => {
    it("when called should return null if nothing is stored against frJwt in localstorage", () => {
      window.localStorage.removeItem("frJwt");
      expect(authentication.getUserCredential("firstname")).toBe(null);
    });
    it("when called should return null if user credential isn't stored in the frJwt in localstorage", () => {
      let frJwt = goodJWTToken;

      window.localStorage.setItem("frJwt", frJwt);
      expect(authentication.getUserCredential("not-a-real-cred")).toBe(null);
    });
    it("when called should return the correct user credential stored in the frJwt in localstorage", () => {
      let frJwt = goodJWTToken;

      window.localStorage.setItem("frJwt", frJwt);
      expect(authentication.getUserCredential("firstname")).toBe("Tom");
    });
    it("if there is an error stored against frJwt in localstorage, it should return null", () => {
      let frJwt = errorJWTToken;
      window.localStorage.setItem("frJwt", frJwt);
      expect(authentication.getUserCredential("firstname")).toBe(null);
    });
  });
  describe("decodeJwtBody", () => {
    test.each`
      scenario           | jwt                                                                                                                                                       | expected
      ${"ASCII"}         | ${"eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiIxMjM0NTY3ODkwIiwibmFtZSI6IkpvaG4gRG9lIn0.signature"}                                                   | ${{ sub: "1234567890", name: "John Doe" }}
      ${"UTF-8"}         | ${"eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJuYW1lIjoiTsOkdsOpbiBTdXBwbGllciJ9.signature"}                                                                  | ${{ name: "Nävén Supplier" }}
      ${"UTF-8 2"}       | ${"eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJjb21wYW55IjoiQWxpYW7Dp2EiLCJuYW1lIjoiSm9zw6kgR29uxb5hxL7Ek8W8In0.rP4c8QotUUNg8wcbXzfhIeHogjtPHc2ki-mWzG1QpE4"} | ${{ company: "Aliança", name: "José Gonžaľēż" }}
      ${"Chinese"}       | ${"eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJjb21wYW55Ijoi6ams5aOr5Z-65Lit5Zu9IiwibmFtZSI6IuWImOWLpCJ9.1G8EPkK1ngcJYDyd3qsK-4Gjr-y9MTssU0UESUebrXY"}        | ${{ company: "马士基中国", name: "刘勤" }}
      ${"simple"}        | ${"eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzaW1wbGUiOiJqd3QifQ.cvI09QALjVQp2xGC9VddagRnD1naJ5RKWT8-vfVh-uY"}                                              | ${{ simple: "jwt" }}
      ${"null"}          | ${null}                                                                                                                                                   | ${null}
      ${"invalid token"} | ${"hello"}                                                                                                                                                | ${null}
    `("Decodes a JWT with $scenario payload", ({ jwt, expected }) => {
      expect(authentication.decodeJwtBody(jwt)).toEqual(expected);
    });
  });
  describe("getCustomerCodeFromJwt", () => {
    it("should return the customer code if a valid jwt", () => {
      let frJwt = goodJWTToken;

      window.localStorage.setItem("frJwt", frJwt);
      expect(authentication.getCustomerCodeFromJwt()).toBe("10000007951");
    });
    it("should return null in case of no jwt", () => {
      window.localStorage.setItem("frJwt", null);
      expect(authentication.getCustomerCodeFromJwt()).toBe(null);
    });
    it("should return null in case of invalid jwt", () => {
      let frJwt = simpleJWTToken;
      window.localStorage.setItem("frJwt", frJwt);
      expect(authentication.getCustomerCodeFromJwt()).toBe(null);
    });
  });
  describe("getSalesForceAccessToken", () => {
    it("when called should return the null if nothing is stored against access_token in localstorage", () => {
      expect(authentication.getSalesForceAccessToken()).toBe(null);
    });
    it("when called should return the JWT stored against customerCode in localstorage", () => {
      const accessToken =
        "00D5r0000008aOX!ARwAQLfW2Gs6ivbsprhxRGP7TaAI9byzdg4jIRUh9W7tEkz6JgShJn.Dsh3uFDYqfGjkOrWaOg9McikT.Zwage1pNvxAVh6Y";
      window.localStorage.setItem("access_token", accessToken);
      expect(authentication.getSalesForceAccessToken()).toBe(accessToken);
    });
  });
  describe("isCustomerLoggedIn", () => {
    test.each`
      token              | expected
      ${goodJWTToken}    | ${true}
      ${simpleJWTToken}  | ${false}
      ${errorJWTToken}   | ${false}
      ${expiredJWTToken} | ${false}
    `("is logged in $expected when token is $token", ({ token, expected }) => {
      window.localStorage.setItem("frJwt", token);
      expect(authentication.isCustomerLoggedIn()).toBe(expected);
    });
  });
});

describe("URL tests", () => {
  const realLocation = global.location;

  beforeAll(() => {
    delete global.location;
    global.location = {
      assign: jest.fn(),
      origin: "https://maersk.com",
      host: "cdt.maersk.com"
    };
    // or even like this if you are also using other location properties (or if TypeScript complains):
    // global.location = { ...realLocation, assign: jest.fn() }
  });

  afterEach(() => {
    global.location.assign.mockClear();
  });

  afterAll(() => {
    global.location = realLocation;
  });

  describe("goToOriginalUrl", () => {
    it("redirects browser to the stored originalUrl", () => {
      localStorage.setItem("originalUrl", "https://maersk.com/originalUrl");
      authentication.goToOriginalUrl();
      expect(global.location.assign).toBeCalledWith("https://maersk.com/originalUrl");
    });
    it("redirects browser to the default redirect(which is dashboard atm)", () => {
      localStorage.removeItem("originalUrl");
      authentication.goToOriginalUrl();
      expect(global.location.assign).toBeCalledWith("https://maersk.com/dashboard/");
    });
  });

  describe("redirectToSSP: Redirect to the SSP Version of dashboard", () => {
    it("navigates to SSP_DASHBOARD configured relative url", () => {
      global.location.host = "maersk.com";
      global.location.hostname = "maersk.com";
      authentication.redirectToSSP();
      expect(global.location.assign).toBeCalledWith("https://maersk.com/l/dashboard");
    });
    it("on localhost, navigates to my-beta CDT", () => {
      global.location.hostname = "localhost";
      authentication.redirectToSSP();
      expect(global.location.assign).toBeCalledWith("https://cdt.maersk.com/l/dashboard");
    });
  });

  describe("redirectToLogin", () => {
    test.each`
      host                | hostname            | path                 | expected
      ${"maersk.com"}     | ${"maersk.com"}     | ${"originPath"}      | ${"https://maersk.com/portaluser/login?originalUrl=https%3A%2F%2Fmaersk.com%2ForiginPath"}
      ${"www.maersk.com"} | ${"www.maersk.com"} | ${"lcl/air?a=1&b=2"} | ${"https://www.maersk.com/portaluser/login?originalUrl=https%3A%2F%2Fwww.maersk.com%2Flcl%2Fair%3Fa%3D1%26b%3D2"}
    `("navigates to login + original url query param", ({ host, hostname, path, expected }) => {
      global.location.host = host;
      global.location.hostname = hostname;
      authentication.redirectToLogin(path);
      expect(global.location.assign).toBeCalledWith(expected);
    });

    test.each`
      host                | hostname            | path                          | expected
      ${"www.maersk.com"} | ${"www.maersk.com"} | ${"lcl/air?a=1&b=2&utm_1=1"}  | ${"https://www.maersk.com/portaluser/login?originalUrl=https%3A%2F%2Fwww.maersk.com%2Flcl%2Fair%3Fa%3D1%26b%3D2%26utm_1%3D1&utm_1=1"}
      ${"www.maersk.com"} | ${"www.maersk.com"} | ${"lcl/air?a=1&b=2&utmm_1=1"} | ${"https://www.maersk.com/portaluser/login?originalUrl=https%3A%2F%2Fwww.maersk.com%2Flcl%2Fair%3Fa%3D1%26b%3D2%26utmm_1%3D1"}
    `(
      "navigates to login + original url query param and adds params that start with utm_",
      ({ host, hostname, path, expected }) => {
        global.location.host = host;
        global.location.hostname = hostname;
        authentication.redirectToLogin(path);
        expect(global.location.assign).toBeCalledWith(expected);
      }
    );

    it("on localhost, navigates to my-beta CDT login app", () => {
      global.jsdom.reconfigure({ url: "http://localhost:8080" });
      global.location.host = "localhost:8080";
      global.location.hostname = "localhost";
      authentication.redirectToLogin("originPath");
      expect(global.location.assign).toBeCalledWith(
        "https://cdt.maersk.com/portaluser/login?originalUrl=https%3A%2F%2Fcdt.maersk.com%2ForiginPath"
      );
    });
  });
});
